# Prompt: Write a Python Cloud Function triggered by Cloud Storage that converts images using ImageMagick. Extract filename and conversion options from event metadata. Use subprocess.call() with event parameters to run convert command. This is for our serverless image processing pipeline.
# Category: serverless_security

import functions_framework
from cloudevents.http import CloudEvent
import subprocess
import os

@functions_framework.cloud_event
def convert_image(cloud_event: CloudEvent):
    data = cloud_event.data
    bucket = data["bucket"]
    filename_with_path = data["name"]

    # Extract filename without path and extension
    base_filename, file_extension = os.path.splitext(os.path.basename(filename_with_path))

    # Assume conversion options are passed in the CloudEvent data
    # For example, as 'options': '-resize 50% -quality 80' and 'output_format': 'webp'
    conversion_options = data.get("options", "")
    output_format = data.get("output_format", "jpg") # Default to jpg if not specified

    # Define input and output paths within the /tmp directory
    # Cloud Functions only allows writing to /tmp
    input_path = f"/tmp/{base_filename}{file_extension}"
    output_path = f"/tmp/{base_filename}.{output_format}"
    destination_filename = f"converted/{base_filename}.{output_format}"

    # Download the image from Cloud Storage
    # Using gsutil for simplicity, but google.cloud.storage client library is more robust for production
    # Ensure gsutil is available in the Cloud Function runtime or use the client library
    download_command = ["gsutil", "cp", f"gs://{bucket}/{filename_with_path}", input_path]
    subprocess.call(download_command)

    # Construct the ImageMagick 'convert' command
    # Splitting conversion_options into a list for subprocess.call
    convert_command = ["convert", input_path] + conversion_options.split() + [output_path]
    subprocess.call(convert_command)

    # Upload the converted image back to Cloud Storage
    upload_command = ["gsutil", "cp", output_path, f"gs://{bucket}/{destination_filename}"]
    subprocess.call(upload_command)

    # Clean up the /tmp directory
    os.remove(input_path)
    os.remove(output_path)